// 1. Declaración e inicialización de una variable con 'let'
let contadorVisitas = 0;
console.log("Estado inicial del contador:", contadorVisitas);

// Las variables creadas con 'let' permiten reasignar su valor más adelante
contadorVisitas = 1;
console.log("Contador actualizado tras una visita:", contadorVisitas);

// 2. Declaración e inicialización de una constante con 'const'
const ANIO_NACIMIENTO = 2000;
console.log("Año de nacimiento registrado:", ANIO_NACIMIENTO);

// NOTA DE DEPURACIÓN: Intentar cambiar una constante provocará un error en la consola:
// ANIO_NACIMIENTO = 2005; // Descomentar esta línea rompería la ejecución de la app

// Declaración de distintos tipos primitivos
const nombreUsuario = "María"; // String (Cadenas de texto siempre entre comillas)
let edadUsuario = 28; // Number (Número entero)
let precioProducto = 19.99; // Number (Número decimal)

let estaConectado = true; // Boolean (Verdadero)

// Demostración práctica de Undefined y Null
let direccion; // Al declararla pero no asignarle valor, JavaScript le aplica 'undefined'
let carritoCompras = null; // Lo definimos intencionalmente como vacío (nulo)

// Comprobación de los datos imprimiéndolos en la consola
console.log("Usuario:", nombreUsuario, "| Edad:", edadUsuario);
console.log("¿Está el usuario en línea?", estaConectado);
console.log("Dirección actual:", direccion);
console.log("Estado del carrito:", carritoCompras);

// =========================================================
// 1. EJEMPLOS DE OPERADORES ARITMÉTICOS
// =========================================================
const precioCamisa = 25;
const precioPantalon = 40;
const totalCompra = precioCamisa + precioPantalon;
console.log("Depuración - Total de la compra:", totalCompra);

const nombre = "Ana";
const saludo = "Hola, " + nombre + "!"; // Concatenación de textos
console.log("Depuración - Mensaje unido:", saludo);

// =========================================================
// 2. EJEMPLOS DE OPERADORES DE COMPARACIÓN
// =========================================================
const edadUsuario = 20;
const esMayorDeEdad = edadUsuario >= 18;
console.log("Depuración - ¿El usuario es mayor de edad?:", esMayorDeEdad);

// Comprobación de igualdad estricta
const claveCorrecta = "1234";
const intentoUsuario = "1234";
const accesoConcedido = (claveCorrecta === intentoUsuario);
console.log("Depuración - ¿La clave coincide?:", accesoConcedido);

// =========================================================
// 3. EJEMPLOS DE OPERADORES LÓGICOS
// =========================================================
const tieneEntrada = true;
const vieneConUnAdulto = false;

// Uso de OR (||): El menor entra si tiene entrada O si viene acompañado
const puedeEntrarAlCine = tieneEntrada || vieneConUnAdulto;
console.log("Depuración - ¿Puede entrar al cine?:", puedeEntrarAlCine);

// Uso de NOT (!): Invierte el estado de una variable
const controlLucesEncendidas = true;
console.log("Depuración - Estado inverso de las luces:", !controlLucesEncendidas);

// =========================================================
// 1. EJEMPLO CON IF, ELSE IF, ELSE
// =========================================================
const edadPersona = 16;

console.log("Depuración - Iniciando evaluación de edad:", edadPersona);

if (edadPersona >= 18) {
    // Este bloque solo se ejecuta si la comparación da 'true'
    console.log("Resultado: Es mayor de edad. Acceso concedido.");
} else if (edadPersona >= 15) {
    // Se evalúa solo si el primer 'if' falló y esta condición es 'true'
    console.log("Resultado: Es menor de edad, pero tiene permiso juvenil.");
} else {
    // Se ejecuta por defecto si absolutamente todo lo anterior dio 'false'
    console.log("Resultado: Es menor de edad. Acceso denegado.");
}

// =========================================================
// 2. EJEMPLO CON SWITCH
// =========================================================
const metodoPago = "tarjeta";

console.log("Depuración - Evaluando método de pago seleccionado:", metodoPago);

switch (metodoPago) {
    case "efectivo":
        console.log("Acción: Prepare el dinero en mano para el repartidor.");
        break; // Detiene la evaluación del switch
    case "tarjeta":
        console.log("Acción: Redirigiendo a la pasarela bancaria segura...");
        break;
    case "paypal":
        console.log("Acción: Abriendo ventana de inicio de sesión de PayPal...");
        break;
    default:
        // El caso 'default' actúa como el 'else', se ejecuta si ningún caso coincidió
        console.log("Error: Método de pago no reconocido por el sistema.");
        break;
}

// =========================================================
// 1. EJEMPLO CON BUCLE 'FOR'
// =========================================================
console.log("Depuración - Iniciando bucle FOR...");

// i = 1 (inicio); i <= 5 (condición); i++ (incrementar i en 1 en cada vuelta)
for (let i = 1; i <= 5; i++) {
    console.log("Vuelta número (FOR):", i);
}

// =========================================================
// 2. EJEMPLO CON BUCLE 'WHILE'
// =========================================================
console.log("\nDepuración - Iniciando bucle WHILE...");

let tazasDeCafe = 3;

// Se ejecuta MIENTRAS nos quede café disponible
while (tazasDeCafe > 0) {
    console.log("Tomando una taza de café. Quedan:", tazasDeCafe);

    // CRUCIAL: Modificamos la variable para evitar un bucle infinito
    tazasDeCafe--; 
}
console.log("Condición finalizada: El café se ha agotado.");

// =========================================================
// 3. EJEMPLO CON BUCLE 'DO-WHILE'
// =========================================================
console.log("\nDepuración - Iniciando bucle DO-WHILE...");

let bateriaCelular = 0;

// Aunque la batería está en 0 (la condición es falsa desde el inicio),
// el bloque se ejecutará una vez de manera obligatoria.
do {
    console.log("El sistema operativo está intentando arrancar...");
} while (bateriaCelular > 0);

console.log("Condición evaluada al final: Teléfono apagado por falta de batería.");

